function solve_typescript_0_2997(items: number[], limit: number): number[] {
  const result = [];
  for (const value of items) {
    if (value >= 0 && value <= limit) result.push(value);
  }
  return result;
}

console.assert(JSON.stringify(solve_typescript_0_2997([1, -1, 5], 3)) === JSON.stringify([1]));
```
Explanation: The solution separates input handling from the core operation.
It names the result clearly and keeps each step small.
